import{c as t,Q as a,j as o,m as r}from"./chunks/framework.BXc4yaFE.js";const u=JSON.parse('{"title":"How Anthropic Engineers Actually Save Tokens","description":"","frontmatter":{"title":"How Anthropic Engineers Actually Save Tokens","author":"@nateherk（Nate Herk）","date":"2026-05-21T00:00:00.000Z","type":"tweet"},"headers":[],"relativePath":"research/tweets/2026-05-21-@nateherk-013627.md","filePath":"research/tweets/2026-05-21-@nateherk-013627.md","lastUpdated":1779894392000}'),n={name:"research/tweets/2026-05-21-@nateherk-013627.md"};function s(h,e,i,l,c,d){return a(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="how-anthropic-engineers-actually-save-tokens" tabindex="-1">How Anthropic Engineers Actually Save Tokens <a class="header-anchor" href="#how-anthropic-engineers-actually-save-tokens" aria-label="Permalink to &quot;How Anthropic Engineers Actually Save Tokens&quot;">​</a></h1><ul><li><strong>作者</strong>：@nateherk（Nate Herk）</li><li><strong>推文連結</strong>：<a href="https://x.com/nateherk/status/2057450555212013627" target="_blank" rel="noreferrer">https://x.com/nateherk/status/2057450555212013627</a></li><li><strong>發布日期</strong>：2026-05-21</li><li><strong>收錄日期</strong>：2026-05-23</li><li><strong>互動數據</strong>：👍 89 · 🔁 5 · 🔖 225 · 👁 42,142</li><li><strong>評分</strong>：7.45/10</li><li><strong>整合決策</strong>：Rule</li></ul><hr><h2 id="tl-dr" tabindex="-1">TL;DR <a class="header-anchor" href="#tl-dr" aria-label="Permalink to &quot;TL;DR&quot;">​</a></h2><p>Claude Code 的 prompt caching 讓 cached tokens 只需支付 10% 費用，1 小時 TTL 是 subscription 預設；避免 mid-session 換模型是保持 cache 最關鍵的單一習慣。</p><hr><h2 id="核心論點" tabindex="-1">核心論點 <a class="header-anchor" href="#核心論點" aria-label="Permalink to &quot;核心論點&quot;">​</a></h2><ol><li><strong>Cached tokens 成本比</strong>：每個 cached token 只花 10% 的 normal input token 費用；91M cached = 實際計費 9M。</li><li><strong>TTL 差異是混亂根源</strong>：Claude Code subscription = 1 小時；API = 5 分鐘；Sub-agents 無論哪個方案永遠是 5 分鐘。</li><li><strong>三層 cache 架構</strong>：system（工具定義）→ project（CLAUDE.md/rules）→ conversation（對話訊息）；越上層改動越貴。</li><li><strong>模型切換會砸爛 cache</strong>：prefix matching 讓每個模型有獨立 cache；切換即全部重算，包括「opus plan」模式的每次切換。</li><li><strong>實用工作流</strong>：idle &gt; 1 小時就開新 session；換任務配合 /clear 不硬 /compact；CLAUDE.md 改動在下次 restart 才生效，mid-session 安全。</li></ol><hr><h2 id="關鍵數據-工具-引用" tabindex="-1">關鍵數據 / 工具 / 引用 <a class="header-anchor" href="#關鍵數據-工具-引用" aria-label="Permalink to &quot;關鍵數據 / 工具 / 引用&quot;">​</a></h2><ul><li><strong>91M tokens in a day</strong>：cached，實際計費如 9M</li><li><strong>Thariq @ Anthropic</strong>：「We actually run alerts on our prompt cache hit rate and declare SEVs if they&#39;re too low.」</li><li><strong>Token Dashboard</strong>：<a href="https://github.com/nateherkai/token-dashboard" target="_blank" rel="noreferrer">https://github.com/nateherkai/token-dashboard</a> — 本地 dashboard，Claude Code 呼叫 setup，即時看 cache create vs cache read per day</li><li>參考文章：<a href="https://x.com/trq212/status/2024574133011673516%EF%BC%88Anthropic" target="_blank" rel="noreferrer">https://x.com/trq212/status/2024574133011673516（Anthropic</a> 工程師 Thariq 的 cache 深度文）</li></ul><hr><h2 id="批判性觀察" tabindex="-1">批判性觀察 <a class="header-anchor" href="#批判性觀察" aria-label="Permalink to &quot;批判性觀察&quot;">​</a></h2><ol><li><strong>Sub-agent TTL 未解釋原因</strong>：文章點出 sub-agents 永遠是 5 分鐘，但沒解釋為何 subscription 無法提升此限制；對 heavy agentic 工作流影響可觀但未被深入討論。</li><li><strong>「opus plan 模式」權衡不完整</strong>：作者說這模式雖然每次切換會清 cache，「long-run 仍有幫助」，但未量化何時值得、何時不值得，使用者難以自行判斷。</li><li><strong>Dashboard 限本地單裝置</strong>：token dashboard 每台機器各自追蹤，跨設備使用者（desktop + laptop）無法獲得整合數據，文中僅一句提及。</li></ol><hr><h2 id="_5-維度評分" tabindex="-1">5 維度評分 <a class="header-anchor" href="#_5-維度評分" aria-label="Permalink to &quot;5 維度評分&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>分數</th><th>說明</th></tr></thead><tbody><tr><td>A. Workspace 可行動性 (30%)</td><td>8</td><td>3 個可直接執行的習慣；dashboard repo 可直接 setup</td></tr><tr><td>B. 創新性 (20%)</td><td>7</td><td>Anthropic SEV 實例 + 1h vs 5m TTL 區分屬內部視角</td></tr><tr><td>C. 證據品質 (20%)</td><td>7</td><td>個人 token 數據 + Anthropic 工程師引言，但無 controlled 測試</td></tr><tr><td>D. 技術深度 (15%)</td><td>7</td><td>prefix matching 機制、三層架構說明清楚但不過深</td></tr><tr><td>E. 泛化性 (15%)</td><td>8</td><td>所有 Claude Code 用戶均適用</td></tr></tbody></table><p><strong>加權總分</strong>：8×0.3 + 7×0.2 + 7×0.2 + 7×0.15 + 8×0.15 = <strong>7.45/10</strong></p><hr><h2 id="整合決策" tabindex="-1">整合決策 <a class="header-anchor" href="#整合決策" aria-label="Permalink to &quot;整合決策&quot;">​</a></h2><p><strong>Rule</strong> — 核心是可操作的通用原則（不換模型、idle &gt; 1h 開新 session、CLAUDE.md mid-session 安全），適合寫入 CLAUDE.md 作為長期行為規則。</p><hr><h2 id="全文" tabindex="-1">全文 <a class="header-anchor" href="#全文" aria-label="Permalink to &quot;全文&quot;">​</a></h2><p>I Saved 300 Million Tokens This Week</p><p>91 million in a single day. 300+ million in a week.</p><p>I didn&#39;t change a single setting. This was prompt caching doing its job in the background.</p><p>But once I actually understood what caching is and how to stop breaking it, my sessions started lasting way longer for the same usage. So here&#39;s the 80/20 of prompt caching in Claude Code, no API deep dive required.</p><h2 id="tl-dr-1" tabindex="-1">TL;DR <a class="header-anchor" href="#tl-dr-1" aria-label="Permalink to &quot;TL;DR&quot;">​</a></h2><p>→ Cached tokens cost 10% of normal input. 91M cached billed like 9M.</p><p>→ Claude Code subscription TTL is 1 hour. API default is 5 minutes. Sub-agents are always 5 minutes.</p><p>→ Cache lives in three layers: system, project, conversation.</p><p>→ Switching models mid-session breaks the cache. Including &quot;opus plan&quot; mode.</p><h2 id="what-caching-actually-costs" tabindex="-1">What Caching Actually Costs <a class="header-anchor" href="#what-caching-actually-costs" aria-label="Permalink to &quot;What Caching Actually Costs&quot;">​</a></h2><p>Every cached token costs 10% of a normal input token.</p><p>So when my dashboard showed 91 million cached on a single day, I got billed like I processed 9 million. That&#39;s the whole reason long Claude Code sessions feel &quot;free&quot; compared to what they would cost without caching.</p><p>Two numbers worth knowing inside the dashboard:</p><p>→ <strong>Cache create.</strong> The one-time cost of writing something into the cache. Pays off the next turn.</p><p>→ <strong>Cache read.</strong> Tokens Claude reused from a cache (your CLAUDE.md, tool definitions, prior messages). 10x cheaper than fresh input.</p><p>If your cache read number is high, you&#39;re winning. If it&#39;s low, you&#39;re paying for the same context over and over.</p><p>Quick quote from Thariq at Anthropic that stuck with me:</p><p>&quot;We actually run alerts on our prompt cache hit rate and declare SEVs if they&#39;re too low.&quot;</p><p>And a great X article by him as well: <a href="https://x.com/trq212/status/2024574133011673516?s=20" target="_blank" rel="noreferrer">https://x.com/trq212/status/2024574133011673516?s=20</a></p><p>When the hit rate is high, four things happen: Claude Code feels faster, their serving cost goes down, your subscription limits feel more generous, and long coding sessions stay practical. When it&#39;s low, everyone loses.</p><p>So the incentives line up. They want your hit rate high. You want it high. The only thing in the way is a handful of small habits that quietly reset everything.</p><h2 id="how-the-cache-grows-each-turn" tabindex="-1">How the Cache Grows Each Turn <a class="header-anchor" href="#how-the-cache-grows-each-turn" aria-label="Permalink to &quot;How the Cache Grows Each Turn&quot;">​</a></h2><p>Cache works on prefix matching. Without going down a rabbit hole, that just means Claude reuses cached tokens as long as everything before that point is identical to what was cached.</p><p>Here&#39;s how a fresh session actually plays out:</p><p>1️⃣ <strong>Turn 1.</strong> No cache yet. The system prompt, your project context (CLAUDE.md, memory, rules), and your first message all get processed fresh and written to cache.</p><p>2️⃣ <strong>Turn 2.</strong> Everything from turn 1 is now cached. Claude only has to process your reply and the next message. Cheap turn.</p><p>3️⃣ <strong>Turn 3.</strong> Same deal. Old turns stay cached. Only the new exchange is fresh.</p><p>The cache is organized in three layers:</p><p>→ <strong>System layer.</strong> Base instructions, tool definitions (read, write, bash, grep, glob), output style. Globally cached.</p><p>→ <strong>Project layer.</strong> CLAUDE.md, memory, project rules. Cached per project.</p><p>→ <strong>Conversation.</strong> Replies and messages. Grow each turn.</p><p>If anything in the system layer or project layer changes mid-session, everything has to be re-cached from scratch. That&#39;s the expensive move. Imagine you&#39;re on message 16 and you change the system prompt or wait an hour. Every token from message 1 onwards has to be reprocessed.</p><h2 id="the-1-hour-vs-5-minute-confusion" tabindex="-1">The 1-Hour vs 5-Minute Confusion <a class="header-anchor" href="#the-1-hour-vs-5-minute-confusion" aria-label="Permalink to &quot;The 1-Hour vs 5-Minute Confusion&quot;">​</a></h2><p>This is where most people get tripped up.</p><p>→ <strong>Claude Code subscription:</strong> 1 hour TTL by default.</p><p>→ <strong>Claude API:</strong> 5 minutes by default. You can bump it to an hour for more cost.</p><p>→ <strong>Sub-agents on any plan:</strong> 5 minutes. Always.</p><p>→ <strong>Claude.ai web chat:</strong> not officially documented. Probably the same as the subscription, but I haven&#39;t confirmed it.</p><p>A few months back when everyone was complaining about Claude subscriptions getting eaten alive, people thought Anthropic had quietly dropped the TTL to 5 minutes without telling anybody. Turns out they didn&#39;t. It&#39;s still 1 hour. But the documentation is split across Claude Code and API pages, which are two very different things, and that&#39;s where a lot of the confusion came from.</p><p>The 5-minute number matters if you&#39;re running heavy sub-agent workflows or using the API directly. For 95% of Claude Code users, the 1-hour window is the only one to care about.</p><h2 id="three-habits-that-cover-95-of-people" tabindex="-1">Three Habits That Cover 95% of People <a class="header-anchor" href="#three-habits-that-cover-95-of-people" aria-label="Permalink to &quot;Three Habits That Cover 95% of People&quot;">​</a></h2><p>Here&#39;s what stood out as actually useful day to day.</p><p>1️⃣ <strong>Don&#39;t pause too long.</strong></p><p>If you&#39;ve been idle for over an hour, everything has fallen out of cache. The next message rebuilds it from scratch. Cheaper to hand off to a fresh session than to resume a stale one.</p><p>2️⃣ <strong>Start fresh when you switch tasks.</strong></p><p>A /compact or /clear breaks the cache anyway, so use that moment to actually reset.</p><p>I built a session handoff skill that&#39;s been my replacement for /compact. It summarizes what we built, the open decisions, the important files, and exactly where to pick back up. Then I /clear, paste the summary, and keep moving like nothing happened.</p><p>The compact command can also take a long time to run. The handoff skill typically finishes in under a minute.</p><p><strong>3️⃣ In Claude chat, use Projects for big docs.</strong></p><p>Caching on claude.ai isn&#39;t documented in detail, but Projects are clearly optimized differently than a thread. If you&#39;re going to paste big documents in, drop them into a Project instead of into the conversation.</p><h2 id="what-quietly-breaks-the-cache" tabindex="-1">What Quietly Breaks the Cache <a class="header-anchor" href="#what-quietly-breaks-the-cache" aria-label="Permalink to &quot;What Quietly Breaks the Cache&quot;">​</a></h2><p>A few things will reset everything without warning.</p><p>→ <strong>Switching the model.</strong> Because of prefix matching, each model has its own cache. The next request reads the entire history with zero cache hits.</p><p>→ <strong>&quot;Opus plan&quot; mode.</strong> This is the setting that uses Opus during plan mode and Sonnet for execution. I&#39;ve recommended it before in token hacks videos for a reason. But it&#39;s important to understand each plan toggle is a model switch, which means a fresh cache each time. Long-run it still helps your session limits. Just know what&#39;s happening under the hood.</p><p>→ <strong>Editing CLAUDE.md mid-session is fine.</strong> The edit doesn&#39;t apply until the next restart, so the live cache stays safe.</p><h2 id="my-free-token-dashboard" tabindex="-1">My Free Token Dashboard <a class="header-anchor" href="#my-free-token-dashboard" aria-label="Permalink to &quot;My Free Token Dashboard&quot;">​</a></h2><p>The screenshots I&#39;ve been pulling are from a token dashboard.</p><p><a href="https://github.com/nateherkai/token-dashboard" target="_blank" rel="noreferrer">https://github.com/nateherkai/token-dashboard</a></p><p>It&#39;s a simple GitHub repo. You give the link to Claude Code, tell it to set it up on localhost, and it pulls in all your past sessions. Not a blank slate. You see your input, output, cache create, and cache read numbers per day from the jump.</p><p>One caveat: the dashboard tracks tokens on a local device. If you switch from your desktop to a laptop, the numbers won&#39;t match. Each machine has its own picture.</p><h2 id="wrap" tabindex="-1">Wrap <a class="header-anchor" href="#wrap" aria-label="Permalink to &quot;Wrap&quot;">​</a></h2><p>Prompt caching is one of those things you can get extremely deep on. The Thoric article goes way further than what&#39;s in here, and it&#39;s worth reading if you want the full picture.</p><p>But you don&#39;t need the full picture to get the benefit. You need the 80/20: cached tokens are 10x cheaper, the TTL is 1 hour on Claude Code, model switches break the cache, and a clean handoff between tasks beats letting a session rot.</p>',86)])])}const g=t(n,[["render",s]]);export{u as __pageData,g as default};
